// ui/icon.go
// Icone PNG embutido como recurso Fyne.
// PNG 256x256 gerado a partir do SVG da impressora matricial Epson FX-80.
// Fyne exige PNG (nao SVG) para o system tray no Windows.

package main

import (
	"encoding/base64"

	"fyne.io/fyne/v2"
)

func printerIcon() fyne.Resource {
	data, _ := base64.StdEncoding.DecodeString(iconBase64)
	return fyne.NewStaticResource("printer.png", data)
}

// iconBase64 e o PNG 256x256 da impressora matricial codificado em base64.
